table.sql:
    	    	insert ignore into CCTIMPUT (siscod, ctacod, movfec, concod, movlet, movnpv, movnro, movimp, movsal, movicc, movife, movipv, movinc) 
    	       select CCT.siscod, CCT.ctacod, CCT.movfec, CCT.concod, CCT.movlet, CCT.movnpv, CCT.movnro, CCT.movsal, 0, [__concod__], '[__movfec__]', [__movnpv__], (select parent from CAJPARAM where parcla = 'nropag' limit 1) from CCTMOVIM CCT where CCT.id_regmovim in ([__numfac__]);


    	       update CCTMOVIM set movsal = 0, movipv = [__movnpv__], movicc = [__concod__] where id_regmovim in ([__numfac__]);
